public final class DBMSQLQueryStoreQueryTextViewBuilder extends ApplicationSQLObjects
{
    str     viewName;
    str     asQueryTextId;
    str     asQuerySqlText;
    str     asStatementSqlHandle;
    str     asIsPartOfEncryptedModule;
    str     asHasRestrictedText;
    str     asRecId;

}

Method.Source:
public static void main(Args args)
{
    var builder = DBMSQLQueryStoreQueryTextViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

private str createSQLStatement()
{
    DictField DictFieldSQLText = new DictField(tableNum(DBMSQLQueryStoreQueryText), fieldNum(DBMSQLQueryStoreQueryText, QuerySQLText));
    str sqlStmt = strFmt(@"SELECT
        r.query_text_id AS %1,"
        +strFmt('CONVERT([NVARCHAR](%1), r.query_sql_text)',DictFieldSQLText.stringLen()) + ' AS ' + asQuerySQLText + ', '+
        @"r.statement_sql_handle AS %2,
        r.is_part_of_encrypted_module AS %3,
        r.has_restricted_text AS %4,
        1010 AS recId
        FROM sys.query_store_query_text r",
    asQueryTextId,
    asStatementSqlHandle,
    asIsPartOfEncryptedModule,
    asHasRestrictedText,
        asRecId);
    return sqlStmt;
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLQueryStoreQueryText));
    viewName            = view.name(DbBackend::Sql);
    asQueryTextId = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryText, QueryTextId)).name(DbBackend::Sql);
    asQuerySqlText = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryText, QuerySqlText)).name(DbBackend::Sql);
    asStatementSqlHandle = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryText, StatementSqlHandle)).name(DbBackend::Sql);
    asIsPartOfEncryptedModule = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryText, IsPartOfEncryptedModule)).name(DbBackend::Sql);
    asHasRestrictedText = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryText, HasRestrictedText)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryText, RecId)).name(DbBackend::Sql);
}

public static DBMSQLQueryStoreQueryTextViewBuilder construct()
{
    return new DBMSQLQueryStoreQueryTextViewBuilder();
}
